+/**
+ * WASM module interface for GNN operations
+ */
+interface GNNWasmModule {
+  /** Build graph from adjacency list */
+  gnn_build_graph(
+    nodeCount: number,
+    edges: Uint32Array,
+    edgeCount: number
+  ): number;
+
+  /** Compute GNN embeddings */
+  gnn_compute_embeddings(
+    graphPtr: number,
+    features: Float32Array,
+    featureDim: number,
+    outputDim: number,
+    layers: number
+  ): Float32Array;
+
+  /** Propagate labels for impact analysis */
+  gnn_propagate(
+    graphPtr: number,
+    initialLabels: Float32Array,
+    iterations: number,
+    dampingFactor: number
+  ): Float32Array;
+
+  /** Community detection using Louvain algorithm */
+  gnn_detect_communities(
+    graphPtr: number,
+    weights: Float32Array
+  ): Uint32Array;
+
+  /** Subgraph matching */
+  gnn_match_subgraph(
+    graphPtr: number,
+    patternPtr: number,
+    threshold: number
+  ): Float32Array;
+
+  /** Free graph */
+  gnn_free(graphPtr: number): void;
+
+  /** Memory management */
+  alloc(size: number): number;
+  dealloc(ptr: number, size: number): void;
+  memory: WebAssembly.Memory;
+}
