+      // Store distances
+      for (let i = 0; i < nodeCount; i++) {
+        distances.set(`${i}-${t}`, dist[i] ?? Infinity);
+      }
+    }
+
+    return distances;
+  }
+}
+
+/**
+ * Create and export default bridge instance
+ */
+export function createMinCutBridge(): IMinCutBridge {
+  return new MinCutBridge();
+}
+
+export default MinCutBridge;

