+function detectLayerViolations(
+  graph: DependencyGraph,
+  layers?: Record<string, string[]>
+): import('./types.js').LayerViolation[] {
+  const violations: import('./types.js').LayerViolation[] = [];
+
+  if (!layers) return violations;
