+function countModules(graph: DependencyGraph): number {
+  const dirs = new Set<string>();
+  for (const node of graph.nodes) {
+    const parts = node.id.split('/');
+    if (parts.length > 1) {
+      dirs.add(parts.slice(0, -1).join('/'));
+    }
+  }
+  return dirs.size;
