+  /** Security settings */
+  security: {
+    /** Allowed root paths */
+    allowedRoots: string[];
+    /** Block sensitive file patterns */
+    blockedPatterns: string[];
+    /** Mask secrets in output */
+    maskSecrets: boolean;
+  };
+}
