+  ewcLambda: number;
+  /** Batch size for training */
+  batchSize: number;
+}
+
+/**
+ * Default configuration
+ */
+const DEFAULT_CONFIG: SonaConfig = {
+  mode: 'balanced',
+  loraRank: 4,
+  learningRate: 0.001,
+  ewcLambda: 100,
+  batchSize: 32,
+};
+
+/**
+ * SONA trajectory for learning
+ */
+export interface SonaTrajectory {
+  id: string;
+  domain: string;
+  steps: SonaStep[];
+  qualityScore: number;
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * SONA learning step
+ */
+export interface SonaStep {
+  stateBefore: Float32Array;
+  action: string;
+  stateAfter: Float32Array;
+  reward: number;
+  timestamp: number;
+}
+
+/**
+ * LoRA weights
+ */
+export interface LoRAWeights {
+  A: Map<string, Float32Array>;
+  B: Map<string, Float32Array>;
+  rank: number;
+  alpha: number;
+}
+
