+        const pattern = patterns.get(patternId);
+        if (pattern) {
+          pattern.usageCount++;
+          const alpha = 1 / pattern.usageCount;
+          pattern.successRate = pattern.successRate * (1 - alpha) + (success ? 1 : 0) * alpha;
